jQuery(document).ready(function($) {
			$('#current_year').text(new Date().getFullYear());
	});;
document.addEventListener("DOMContentLoaded", function () {
    const form = document.querySelector('#forminator-module-3430'); 

    if (form) {
        form.addEventListener('submit', function (e) {
            // Get the two fields by name or ID
            const fieldA = form.querySelector('[name="upload-1"]'); 
            const fieldB = form.querySelector('[name="url-1"]'); 

            if (
                (!fieldA.value || fieldA.value.trim() === '') &&
                (!fieldB.value || fieldB.value.trim() === '')
            ) {
                // show error message
                form.querySelector('#custom-error').style.display = "block";

                //and highlight fields
                fieldB.style.borderColor = 'red';
				
				e.preventDefault(); // stop form submission
				e.stopImmediatePropagation();
            }
			else {
				form.querySelector('#custom-error').style.display = "none";
				fieldB.style.borderColor = '#333';
			}
        });
	}
});

jQuery(window).on('load', function() {
    document.addEventListener('forminator:form:submit:success', function(event) {
        let targetFormId = 3430;
        console.log('outside submit success');

        if (event.detail && event.detail.form_id === targetFormId) {
            let form = event.target;
            console.log('inside submit success');
            jQuery(form).find('select').val(null).trigger('change.select2');
        }
    });
});